"use client"

import { useState } from "react"
import { useDataStore } from "@/store/data-store"
import { useAuthStore } from "@/store/auth-store"
import { PageHeader } from "@/components/shared/page-header"
import { EntityStatusBadge } from "@/components/shared/status-badge"
import { ConfirmDialog } from "@/components/shared/confirm-dialog"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  MoreHorizontal,
  Pencil,
  Trash2,
  Search,
  UserCog,
  Eye,
  Users,
  GitBranch,
  FileText,
  Crown,
} from "lucide-react"
import type { Team, EntityStatus } from "@/lib/types"
import { toast } from "sonner"

export default function TeamsPage() {
  const { currentUser } = useAuthStore()
  const {
    teams,
    engineers,
    addTeam,
    updateTeam,
    deleteTeam,
    getBranchesByDMA,
    getEngineersByDMA,
    getTeamsByDMA,
  } = useDataStore()
  const [search, setSearch] = useState("")
  const [dialogOpen, setDialogOpen] = useState(false)
  const [detailOpen, setDetailOpen] = useState(false)
  const [editingTeam, setEditingTeam] = useState<Team | null>(null)
  const [viewingTeam, setViewingTeam] = useState<Team | null>(null)
  const [deleteId, setDeleteId] = useState<string | null>(null)

  // Form state
  const [formName, setFormName] = useState("")
  const [formBranchId, setFormBranchId] = useState("")
  const [formLeaderId, setFormLeaderId] = useState("")
  const [formEngineerIds, setFormEngineerIds] = useState<string[]>([])
  const [formStatus, setFormStatus] = useState<EntityStatus>("active")

  // Only DMA managers can access this page
  const isDMAManager = currentUser?.role === "dma_manager"
  if (!isDMAManager) {
    return (
      <div className="flex flex-col gap-6">
        <PageHeader
          title="Teams Management"
          description="Only DMA Managers can manage teams"
        />
        <Card>
          <CardContent className="py-12 text-center text-muted-foreground">
            You do not have permission to access this page. Only DMA Managers can manage teams.
          </CardContent>
        </Card>
      </div>
    )
  }

  const dmaId = currentUser?.dmaId ?? ""
  const myBranches = getBranchesByDMA(dmaId)
  const myEngineers = getEngineersByDMA(dmaId)
  const myTeams = getTeamsByDMA(dmaId)

  const filteredTeams = myTeams.filter(
    (t) =>
      t.name.toLowerCase().includes(search.toLowerCase()) ||
      t.branchName.toLowerCase().includes(search.toLowerCase()) ||
      t.leaderName.toLowerCase().includes(search.toLowerCase())
  )

  // Get available engineers for team formation (those in the selected branch)
  const availableEngineers = formBranchId
    ? myEngineers.filter((e) => e.branchId === formBranchId)
    : []

  function openCreateDialog() {
    setEditingTeam(null)
    setFormName("")
    setFormBranchId("")
    setFormLeaderId("")
    setFormEngineerIds([])
    setFormStatus("active")
    setDialogOpen(true)
  }

  function openEditDialog(team: Team) {
    setEditingTeam(team)
    setFormName(team.name)
    setFormBranchId(team.branchId)
    setFormLeaderId(team.leaderId)
    setFormEngineerIds(team.engineerIds)
    setFormStatus(team.status)
    setDialogOpen(true)
  }

  function handleSubmit() {
    if (!formName.trim()) {
      toast.error("Team name is required")
      return
    }
    if (!formBranchId) {
      toast.error("Please select a branch")
      return
    }
    if (!formLeaderId) {
      toast.error("Please select a team leader")
      return
    }

    const branch = myBranches.find((b) => b.id === formBranchId)
    const leader = myEngineers.find((e) => e.id === formLeaderId)

    // Validate team leader is from the selected branch
    if (leader?.branchId !== formBranchId) {
      toast.error("Team leader must be from the selected branch")
      return
    }

    const allIds = formEngineerIds.includes(formLeaderId)
      ? formEngineerIds
      : [formLeaderId, ...formEngineerIds]

    // Validate all team members are from the same branch
    const invalidEngineers = allIds.filter((id) => {
      const engineer = myEngineers.find((e) => e.id === id)
      return engineer?.branchId !== formBranchId
    })

    if (invalidEngineers.length > 0) {
      toast.error("All team members must be from the same branch")
      return
    }

    // Ensure all team members are from the same DMA and utility
    const firstEngineer = myEngineers.find((e) => e.id === allIds[0])
    const invalidMembers = allIds.filter((id) => {
      const engineer = myEngineers.find((e) => e.id === id)
      return engineer?.dmaId !== firstEngineer?.dmaId || 
             engineer?.utilityId !== firstEngineer?.utilityId
    })

    if (invalidMembers.length > 0) {
      toast.error("All team members must be from the same Utility and DMA")
      return
    }

    if (editingTeam) {
      updateTeam(editingTeam.id, {
        name: formName,
        branchId: formBranchId,
        branchName: branch?.name ?? "",
        leaderId: formLeaderId,
        leaderName: leader?.name ?? "",
        engineerIds: allIds,
        status: formStatus,
      })
      toast.success("Team updated successfully")
    } else {
      addTeam({
        name: formName,
        branchId: formBranchId,
        branchName: branch?.name ?? "",
        dmaId,
        leaderId: formLeaderId,
        leaderName: leader?.name ?? "",
        engineerIds: allIds,
        status: formStatus,
      })
      toast.success("Team created successfully")
    }

    setDialogOpen(false)
  }

  function handleDelete() {
    if (deleteId) {
      deleteTeam(deleteId)
      toast.success("Team deleted successfully")
      setDeleteId(null)
    }
  }

  function toggleEngineer(engId: string) {
    setFormEngineerIds((prev) =>
      prev.includes(engId) ? prev.filter((id) => id !== engId) : [...prev, engId]
    )
  }

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        title="Team Management"
        description="Create and manage teams within your DMA"
        actionLabel="Create Team"
        actionIcon={UserCog}
        onAction={openCreateDialog}
      />

      {/* Search */}
      <div className="relative max-w-sm">
        <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
        <Input
          placeholder="Search teams..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="pl-9"
        />
      </div>

      {/* Team cards grid */}
      {filteredTeams.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <UserCog className="h-12 w-12 text-muted-foreground/30" />
            <p className="mt-3 text-sm text-muted-foreground">
              No teams found
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid grid-cols-1 gap-4 md:grid-cols-2 xl:grid-cols-3">
          {filteredTeams.map((team) => {
            const teamEngineers = engineers.filter((e) =>
              team.engineerIds.includes(e.id)
            )
            return (
              <Card
                key={team.id}
                className="transition-all duration-200 hover:shadow-md hover:-translate-y-0.5"
              >
                <CardContent className="p-5">
                  <div className="flex items-start justify-between">
                    <div className="flex items-center gap-3">
                      <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary/10">
                        <UserCog className="h-5 w-5 text-primary" />
                      </div>
                      <div>
                        <h3 className="text-sm font-semibold">{team.name}</h3>
                        <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                          <GitBranch className="h-3 w-3" />
                          {team.branchName}
                        </div>
                      </div>
                    </div>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-8 w-8"
                        >
                          <MoreHorizontal className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem
                          onClick={() => {
                            setViewingTeam(team)
                            setDetailOpen(true)
                          }}
                        >
                          <Eye className="mr-2 h-4 w-4" />
                          View Details
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={() => openEditDialog(team)}
                        >
                          <Pencil className="mr-2 h-4 w-4" />
                          Edit
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={() => setDeleteId(team.id)}
                          className="text-red-600 focus:text-red-600"
                        >
                          <Trash2 className="mr-2 h-4 w-4" />
                          Delete
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </div>

                  <div className="mt-4 flex items-center gap-1.5">
                    <Crown className="h-3.5 w-3.5 text-amber-500" />
                    <span className="text-xs font-medium">
                      {team.leaderName}
                    </span>
                    <EntityStatusBadge status={team.status} />
                  </div>

                  <div className="mt-3 flex items-center gap-4 text-xs text-muted-foreground">
                    <div className="flex items-center gap-1">
                      <Users className="h-3 w-3" />
                      {team.memberCount} members
                    </div>
                    <div className="flex items-center gap-1">
                      <FileText className="h-3 w-3" />
                      {team.activeReports} active reports
                    </div>
                  </div>

                  {/* Mini member list */}
                  <div className="mt-3 flex flex-wrap gap-1">
                    {teamEngineers.slice(0, 4).map((eng) => (
                      <Badge
                        key={eng.id}
                        variant="secondary"
                        className="text-[10px]"
                      >
                        {eng.name.split(" ")[0]}
                      </Badge>
                    ))}
                    {teamEngineers.length > 4 && (
                      <Badge variant="outline" className="text-[10px]">
                        +{teamEngineers.length - 4}
                      </Badge>
                    )}
                  </div>
                </CardContent>
              </Card>
            )
          })}
        </div>
      )}

      {/* Detail Dialog */}
      <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Team Details</DialogTitle>
          </DialogHeader>
          {viewingTeam && (
            <div className="flex flex-col gap-4 py-4">
              <div className="flex items-center gap-4">
                <div className="flex h-12 w-12 items-center justify-center rounded-xl bg-primary/10">
                  <UserCog className="h-6 w-6 text-primary" />
                </div>
                <div>
                  <h3 className="text-lg font-semibold">{viewingTeam.name}</h3>
                  <p className="text-sm text-muted-foreground">
                    {viewingTeam.branchName}
                  </p>
                </div>
                <EntityStatusBadge status={viewingTeam.status} />
              </div>

              <div className="grid grid-cols-3 gap-3 rounded-lg bg-muted/50 p-4">
                <div className="text-center">
                  <p className="text-lg font-bold">
                    {viewingTeam.memberCount}
                  </p>
                  <p className="text-xs text-muted-foreground">Members</p>
                </div>
                <div className="text-center">
                  <p className="text-lg font-bold">
                    {viewingTeam.activeReports}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    Active Reports
                  </p>
                </div>
                <div className="text-center">
                  <p className="text-lg font-bold text-amber-600">
                    {viewingTeam.leaderName.split(" ")[0]}
                  </p>
                  <p className="text-xs text-muted-foreground">Leader</p>
                </div>
              </div>

              <div>
                <h4 className="mb-2 text-sm font-semibold">Team Members</h4>
                <div className="flex flex-col gap-2">
                  {engineers
                    .filter((e) =>
                      viewingTeam.engineerIds.includes(e.id)
                    )
                    .map((eng) => (
                      <div
                        key={eng.id}
                        className="flex items-center justify-between rounded-lg border px-3 py-2"
                      >
                        <div className="flex items-center gap-2">
                          <Users className="h-4 w-4 text-muted-foreground" />
                          <span className="text-sm">{eng.name}</span>
                          {eng.id === viewingTeam.leaderId && (
                            <Badge className="text-[10px]">Leader</Badge>
                          )}
                        </div>
                        <EntityStatusBadge status={eng.status} />
                      </div>
                    ))}
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>
              {editingTeam ? "Edit Team" : "Create Team"}
            </DialogTitle>
          </DialogHeader>
          <div className="flex flex-col gap-4 py-4">
            <div className="flex flex-col gap-2">
              <Label htmlFor="team-name">Team Name</Label>
              <Input
                id="team-name"
                value={formName}
                onChange={(e) => setFormName(e.target.value)}
                placeholder="e.g., Team Alpha"
              />
            </div>
            <div className="flex flex-col gap-2">
              <Label>Branch</Label>
              <Select
                value={formBranchId}
                onValueChange={(v) => {
                  setFormBranchId(v)
                  setFormLeaderId("")
                  setFormEngineerIds([])
                }}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select branch" />
                </SelectTrigger>
                <SelectContent>
                  {myBranches.map((b) => (
                    <SelectItem key={b.id} value={b.id}>
                      {b.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex flex-col gap-2">
              <Label>Team Leader</Label>
              <Select
                value={formLeaderId}
                onValueChange={setFormLeaderId}
                disabled={!formBranchId}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select leader" />
                </SelectTrigger>
                <SelectContent>
                  {availableEngineers
                    .filter((e) => e.status === "active")
                    .map((e) => (
                      <SelectItem key={e.id} value={e.id}>
                        {e.name}
                      </SelectItem>
                    ))}
                </SelectContent>
              </Select>
            </div>
            {formBranchId && (
              <div className="flex flex-col gap-2">
                <Label>
                  Team Members ({formEngineerIds.length} selected)
                </Label>
                <div className="max-h-40 overflow-y-auto rounded-lg border p-2">
                  {availableEngineers
                    .filter((e) => e.id !== formLeaderId)
                    .map((eng) => (
                      <button
                        key={eng.id}
                        type="button"
                        onClick={() => toggleEngineer(eng.id)}
                        className={`flex w-full items-center justify-between rounded-md px-3 py-2 text-sm transition-colors ${
                          formEngineerIds.includes(eng.id)
                            ? "bg-primary/10 text-primary"
                            : "hover:bg-muted/50"
                        }`}
                      >
                        <span>{eng.name}</span>
                        {formEngineerIds.includes(eng.id) && (
                          <Badge variant="default" className="text-[10px]">
                            Selected
                          </Badge>
                        )}
                      </button>
                    ))}
                  {availableEngineers.filter(
                    (e) => e.id !== formLeaderId
                  ).length === 0 && (
                    <p className="py-2 text-center text-xs text-muted-foreground">
                      No other engineers in this branch
                    </p>
                  )}
                </div>
              </div>
            )}
            <div className="flex flex-col gap-2">
              <Label>Status</Label>
              <Select
                value={formStatus}
                onValueChange={(v) => setFormStatus(v as EntityStatus)}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="active">Active</SelectItem>
                  <SelectItem value="inactive">Inactive</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleSubmit}>
              {editingTeam ? "Save Changes" : "Create Team"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <ConfirmDialog
        open={!!deleteId}
        onOpenChange={() => setDeleteId(null)}
        title="Delete Team"
        description="Are you sure you want to delete this team? Engineers will remain but become unassigned. This action cannot be undone."
        confirmLabel="Delete Team"
        onConfirm={handleDelete}
      />
    </div>
  )
}
